const name = $json["What is your full name?"] || "";
const email = $json["What is your email address?"] || "";
const message = $json["What project can we help you with today?"] || "";

// Title Case Name
function toTitleCase(str) {
  return str
    .toLowerCase()
    .split(" ")
    .map(word => word.charAt(0).toUpperCase() + word.slice(1))
    .join(" ");
}

// Extract domain
const domain = email.split("@")[1] || "";

return [
  {
    json: {
      Name: toTitleCase(name.trim()),
      Email: email.trim().toLowerCase(),
      Message: message.trim(),
      Domain: domain
    }
  }
];

